async function processUploadedImage(file, is = false) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      if (isMobileDevice() && !is) {
        const img = new Image();
        img.onload = () => {
          const canvas = document.createElement("canvas");
          canvas.width = img.width;
          canvas.height = img.height;
          const ctx = canvas.getContext("2d");
          ctx.drawImage(img, 0, 0);
          const dataUrl = canvas.toDataURL("image/jpeg", 0.3);
          addLog(`\u56FE\u7247\u5DF2\u5728\u79FB\u52A8\u7AEF\u538B\u7F29 (JPEG \u8D28\u91CF 0.3).`);
          resolve(dataUrl);
        };
        img.onerror = (err) => reject(new Error("\u56FE\u7247\u52A0\u8F7D\u5931\u8D25."));
        img.src = e.target.result;
      } else {
        addLog(`\u684C\u9762\u7AEF\u56FE\u7247\u5DF2\u52A0\u8F7D.`);
        resolve(e.target.result);
      }
    };
    reader.onerror = (err) => reject(new Error("\u6587\u4EF6\u8BFB\u53D6\u5931\u8D25."));
    reader.readAsDataURL(file);
  });
}
async function processUploadedImageToBlob(file) {
  if (isMobileDevice()) {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = (e) => {
        const img = new Image();
        img.onload = () => {
          const canvas = document.createElement("canvas");
          canvas.width = img.width;
          canvas.height = img.height;
          const ctx = canvas.getContext("2d");
          ctx.drawImage(img, 0, 0);
          canvas.toBlob(
            (blob) => {
              if (blob) {
                addLog(`\u56FE\u7247\u5DF2\u5728\u79FB\u52A8\u7AEF\u538B\u7F29 (JPEG \u8D28\u91CF 0.5). \u539F\u59CB\u5927\u5C0F: ${file.size} bytes, \u538B\u7F29\u540E\u5927\u5C0F: ${blob.size} bytes`);
                resolve(blob);
              } else {
                reject(new Error("Canvas to Blob \u8F6C\u6362\u5931\u8D25."));
              }
            },
            "image/jpeg",
            0.5
          );
        };
        img.onerror = (err) => reject(new Error("\u56FE\u7247\u52A0\u8F7D\u5931\u8D25."));
        img.src = e.target.result;
      };
      reader.onerror = (err) => reject(new Error("\u6587\u4EF6\u8BFB\u53D6\u5931\u8D25."));
      reader.readAsDataURL(file);
    });
  } else {
    addLog(`\u684C\u9762\u7AEF\u56FE\u7247\u5DF2\u52A0\u8F7D. \u5927\u5C0F: ${file.size} bytes`);
    return Promise.resolve(file);
  }
}
