  const uniqueCleanedTags = [...new Set(cleanedTagsForTranslation)];
  toastr.info("\u6B63\u5728\u7FFB\u8BD1\u670D\u88C5\u63CF\u8FF0...", "\u8BF7\u7A0D\u5019", { timeOut: 0, extendedTimeOut: 0 });
