function parseThinkingContent(text) {
  if (!text || typeof text !== "string") {
    return {
      hasThinking: false,
      thinkingBlocks: [],
      cleanedText: text || ""
    };
  }
  const thinkingBlocks = [];
  let cleanedText = text;
  const lastCloseIndex = text.lastIndexOf("</think>");
  if (lastCloseIndex !== -1) {
    const thinkingContent = text.substring(0, lastCloseIndex).trim();
    if (thinkingContent.length > 0) {
      const cleanThinkingContent = thinkingContent.replace(/<\/?think>/gi, "").trim();
      if (cleanThinkingContent.length > 0) {
        const truncatedContent = cleanThinkingContent.length > 10240 ? cleanThinkingContent.substring(0, 10240) + "\n...(\u5185\u5BB9\u8FC7\u957F\u5DF2\u622A\u65AD)" : cleanThinkingContent;
        thinkingBlocks.push({
          content: truncatedContent,
          startIndex: 0,
          index: 0
        });
      }
    }
    cleanedText = text.substring(lastCloseIndex + 8).trim();
  }
  return {
    hasThinking: thinkingBlocks.length > 0,
    thinkingBlocks,
    cleanedText
  };
}
